// This handler uses the pagination, filtering, and sorting
// context provided by the api-endpoint node

const query = msg.req.query || {};

// Mock order data
const allOrders = [
    { id: 'ord-001', customerId: 'cust-1', status: 'completed', total: 150.00, createdAt: '2024-03-15T10:30:00Z' },
    { id: 'ord-002', customerId: 'cust-2', status: 'pending', total: 89.99, createdAt: '2024-03-15T11:45:00Z' },
    { id: 'ord-003', customerId: 'cust-1', status: 'processing', total: 299.99, createdAt: '2024-03-14T09:00:00Z' },
    { id: 'ord-004', customerId: 'cust-3', status: 'completed', total: 49.99, createdAt: '2024-03-14T14:20:00Z' },
    { id: 'ord-005', customerId: 'cust-2', status: 'shipped', total: 199.00, createdAt: '2024-03-13T16:00:00Z' },
    { id: 'ord-006', customerId: 'cust-4', status: 'pending', total: 75.50, createdAt: '2024-03-13T08:30:00Z' },
    { id: 'ord-007', customerId: 'cust-1', status: 'completed', total: 450.00, createdAt: '2024-03-12T12:00:00Z' },
    { id: 'ord-008', customerId: 'cust-5', status: 'cancelled', total: 125.00, createdAt: '2024-03-12T10:15:00Z' },
    { id: 'ord-009', customerId: 'cust-3', status: 'processing', total: 88.88, createdAt: '2024-03-11T15:45:00Z' },
    { id: 'ord-010', customerId: 'cust-2', status: 'completed', total: 567.00, createdAt: '2024-03-11T09:30:00Z' },
    { id: 'ord-011', customerId: 'cust-4', status: 'shipped', total: 234.56, createdAt: '2024-03-10T14:00:00Z' },
    { id: 'ord-012', customerId: 'cust-1', status: 'pending', total: 99.99, createdAt: '2024-03-10T11:20:00Z' }
];

let filteredOrders = [...allOrders];

// Apply filters from msg.filtering (populated by api-endpoint)
const filtering = msg.filtering || {};
const appliedFilters = {};

// Manual filtering (in production, use generated WHERE clause with database)
if (query.status) {
    const statuses = query.status.split(',');
    filteredOrders = filteredOrders.filter(o => statuses.includes(o.status));
    appliedFilters.status = statuses;
}

if (query.customerId) {
    filteredOrders = filteredOrders.filter(o => o.customerId === query.customerId);
    appliedFilters.customerId = query.customerId;
}

if (query.minTotal) {
    const minTotal = parseFloat(query.minTotal);
    filteredOrders = filteredOrders.filter(o => o.total >= minTotal);
    appliedFilters.minTotal = minTotal;
}

if (query.maxTotal) {
    const maxTotal = parseFloat(query.maxTotal);
    filteredOrders = filteredOrders.filter(o => o.total <= maxTotal);
    appliedFilters.maxTotal = maxTotal;
}

// Apply sorting from msg.sorting (populated by api-endpoint)
const sorting = msg.sorting || {};
const sortField = query.sort ? query.sort.replace(/^-/, '') : 'createdAt';
const sortDesc = query.sort ? query.sort.startsWith('-') : true;

filteredOrders.sort((a, b) => {
    let aVal = a[sortField];
    let bVal = b[sortField];

    if (typeof aVal === 'string') {
        aVal = aVal.toLowerCase();
        bVal = bVal.toLowerCase();
    }

    if (aVal < bVal) return sortDesc ? 1 : -1;
    if (aVal > bVal) return sortDesc ? -1 : 1;
    return 0;
});

// Apply pagination from msg.pagination (populated by api-endpoint)
const pagination = msg.pagination || {};
const page = parseInt(query.page) || 1;
const limit = parseInt(query.limit) || 20;
const offset = (page - 1) * limit;

const total = filteredOrders.length;
const totalPages = Math.ceil(total / limit);
const paginatedOrders = filteredOrders.slice(offset, offset + limit);

msg.res.json({
    data: paginatedOrders,
    pagination: {
        page: page,
        limit: limit,
        total: total,
        totalPages: totalPages,
        hasNext: page < totalPages,
        hasPrev: page > 1,
        // Links for convenience
        nextPage: page < totalPages ? page + 1 : null,
        prevPage: page > 1 ? page - 1 : null
    },
    filters: appliedFilters,
    sorting: {
        field: sortField,
        direction: sortDesc ? 'desc' : 'asc'
    },
    // Include SQL clauses for reference (useful when debugging database queries)
    _debug: {
        whereClause: filtering.whereClause || null,
        orderByClause: sorting.orderByClause || null
    }
});

return null;

// Cursor-based pagination is ideal for:
// - Real-time data streams
// - Large datasets
// - Infinite scroll UIs
// - Avoiding duplicate/missing items when data changes

const query = msg.req.query || {};

// Mock event stream (sorted by timestamp descending)
const allEvents = [];
for (let i = 1; i <= 50; i++) {
    const date = new Date();
    date.setMinutes(date.getMinutes() - i * 5);
    allEvents.push({
        id: `evt-${String(i).padStart(3, '0')}`,
        type: ['user.login', 'user.logout', 'order.created', 'payment.processed', 'notification.sent'][i % 5],
        payload: { index: i },
        timestamp: date.toISOString()
    });
}

let filteredEvents = [...allEvents];

// Apply type filter
if (query.type) {
    filteredEvents = filteredEvents.filter(e => e.type === query.type);
}

// Decode cursor (in production, this would be a secure, opaque token)
let startIndex = 0;
if (query.cursor) {
    try {
        const decoded = JSON.parse(Buffer.from(query.cursor, 'base64').toString());
        startIndex = decoded.index || 0;
    } catch (e) {
        // Invalid cursor, start from beginning
        startIndex = 0;
    }
}

const limit = parseInt(query.limit) || 20;

// Get page of results
const pageEvents = filteredEvents.slice(startIndex, startIndex + limit);
const hasMore = startIndex + limit < filteredEvents.length;

// Generate next cursor
let nextCursor = null;
if (hasMore) {
    nextCursor = Buffer.from(JSON.stringify({
        index: startIndex + limit,
        // Include a timestamp for cursor expiration in production
        ts: Date.now()
    })).toString('base64');
}

msg.res.json({
    data: pageEvents,
    pagination: {
        cursor: query.cursor || null,
        nextCursor: nextCursor,
        hasMore: hasMore,
        limit: limit,
        // For cursor pagination, we typically don't expose total count
        // as it can be expensive to compute
        count: pageEvents.length
    }
});

return null;

// This endpoint demonstrates caching combined with filtering
// Cache key includes the full query string, so different filters = different cache entries

const query = msg.req.query || {};

// Check if this was a cache hit
if (msg.cache && msg.cache.hit) {
    // Response was already sent from cache
    return null;
}

// Mock product catalog
const allProducts = [
    { id: 'p1', name: 'Laptop Pro', category: 'electronics', price: 1299.99, inStock: true },
    { id: 'p2', name: 'Wireless Mouse', category: 'electronics', price: 49.99, inStock: true },
    { id: 'p3', name: 'USB-C Hub', category: 'electronics', price: 79.99, inStock: false },
    { id: 'p4', name: 'Standing Desk', category: 'furniture', price: 599.00, inStock: true },
    { id: 'p5', name: 'Office Chair', category: 'furniture', price: 349.00, inStock: true },
    { id: 'p6', name: 'Desk Lamp', category: 'furniture', price: 89.99, inStock: false },
    { id: 'p7', name: 'Notebook Set', category: 'office', price: 24.99, inStock: true },
    { id: 'p8', name: 'Pen Collection', category: 'office', price: 39.99, inStock: true },
    { id: 'p9', name: 'Mechanical Keyboard', category: 'electronics', price: 159.99, inStock: true },
    { id: 'p10', name: 'Monitor 27"', category: 'electronics', price: 449.99, inStock: true },
    { id: 'p11', name: 'Webcam HD', category: 'electronics', price: 99.99, inStock: false },
    { id: 'p12', name: 'File Cabinet', category: 'furniture', price: 189.00, inStock: true }
];

let filtered = [...allProducts];

// Apply filters
if (query.category) {
    filtered = filtered.filter(p => p.category === query.category);
}

if (query.inStock !== undefined) {
    const inStock = query.inStock === 'true' || query.inStock === true;
    filtered = filtered.filter(p => p.inStock === inStock);
}

if (query.minPrice) {
    filtered = filtered.filter(p => p.price >= parseFloat(query.minPrice));
}

if (query.maxPrice) {
    filtered = filtered.filter(p => p.price <= parseFloat(query.maxPrice));
}

// Apply sorting
const sortField = query.sort ? query.sort.replace(/^-/, '') : 'name';
const sortDesc = query.sort ? query.sort.startsWith('-') : false;

filtered.sort((a, b) => {
    let aVal = a[sortField];
    let bVal = b[sortField];
    if (typeof aVal === 'string') {
        aVal = aVal.toLowerCase();
        bVal = bVal.toLowerCase();
    }
    if (aVal < bVal) return sortDesc ? 1 : -1;
    if (aVal > bVal) return sortDesc ? -1 : 1;
    return 0;
});

// Apply pagination
const page = parseInt(query.page) || 1;
const limit = parseInt(query.limit) || 10;
const offset = (page - 1) * limit;
const paginated = filtered.slice(offset, offset + limit);

const response = {
    products: paginated,
    meta: {
        pagination: {
            page,
            limit,
            total: filtered.length,
            totalPages: Math.ceil(filtered.length / limit)
        },
        cache: {
            cached: false,
            ttl: 30000,
            key: msg.cache?.key || null
        }
    }
};

msg.res.json(response);

return null;
